function toBinary(number)
    if number == 0 then return "00000000" end
    if number < 0 then 
        return "-" .. toBinary(-number) 
    end
    
    local binary = ""
    while number > 0 do
        binary = tostring(number % 2) .. binary
        number = math.floor(number / 2)
    end
    
    return string.rep("0", 8 - #binary) .. binary
end

local frame = 1
local video = BadApple()

onEvent("RenderEvent", function()
	local drawList = ImGui.GetForegroundDrawList()
	
    frame = frame + video.fps/20
	
	if tonumber(frame) >= video.frame_count then
		frame = 1
	end
	
	local video_frame = video.frames[math.floor(frame)]

	for y = 1, 48 do
		local video_frame_line = video_frame[y]
		for x = 8, 64, 8 do
			local pc = video_frame_line[math.floor(x/8)]
			
			local bit8 = toBinary(pc)
			
			for i = 1,8 do
				local pixel = bit8:sub(i, i)
				local rgb_pixel
				if pixel == "1" then
					rgb_pixel = {255,255,255,255}
				else
					rgb_pixel = {0,0,0,255}
				end
                drawList:AddRectFilled({ x*10+(i*10), y*10 }, { x*10+(i*10)+10, y*10+10 }, rgb_pixel,0,0)
			end
		end
	end
end)